#include <stdio.h>
#define MOD 1000000007
int dp[101];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A0, A1, A2, A3, S;
        scanf("%d %d %d %d %d", &A0, &A1, &A2, &A3, &S);
        dp[0] = 1;
        for (int i = 1; i <= S; i++) dp[i] = 0;
        for (int N = 1; N <= S; N++) {
            int num = (A0 + A1 * N + A2 * N * N + A3 * N * N * N) % MOD;
            for (int i = N; i <= S; i++) {
                dp[i] = (dp[i] + (long long)dp[i - N] * num) % MOD;
            }
        }
        printf("%d\n", dp[S]);
    }
    return 0;
}

